import{c as d,Q as a,j as t,m as r}from"./chunks/framework.BkjtU8k0.js";const n=JSON.parse('{"title":"文档导览","description":"","frontmatter":{},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md","lastUpdated":1779263197000}'),i={name:"guide/index.md"};function o(c,e,l,h,s,f){return a(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="文档导览" tabindex="-1">文档导览 <a class="header-anchor" href="#文档导览" aria-label="Permalink to &quot;文档导览&quot;">​</a></h1><div class="doc-kicker">Start From The Right Door</div><p class="doc-lead"> Flyfish Viewer 官方文档同时承担组件主页、接入手册和成品交付说明。 文档围绕真实交付路径组织: 先确认支持格式和 Demo 表现，再选择 Vue3、Vue2、React、纯 JS 或 iframe 嵌入，最后了解安装、私有化部署和成品分发。 </p><div class="doc-link-row"><a href="https://doc.flyfish.dev" target="_blank" rel="noreferrer">官方文档</a><a href="https://viewer.flyfish.dev" target="_blank" rel="noreferrer">在线 Demo</a><a href="https://github.com/flyfish-dev/file-viewer" target="_blank" rel="noreferrer">GitHub 成品仓库</a><a href="/guide/quickstart">快速开始</a><a href="/guide/formats">支持格式</a><a href="/guide/usage">组件用法</a><a href="/guide/distribution">发布分发</a></div><h2 id="优秀之处" tabindex="-1">优秀之处 <a class="header-anchor" href="#优秀之处" aria-label="Permalink to &quot;优秀之处&quot;">​</a></h2><div class="doc-grid"><div class="doc-card"><h3>纯前端 Serverless</h3><p>主要解析和渲染工作在浏览器完成，减少后端转码服务、临时文件和任务队列带来的维护成本。</p></div><div class="doc-card"><h3>覆盖真实附件场景</h3><p>内置 74 个扩展名映射，覆盖 Office、PDF、OFD、CAD、Excalidraw、draw.io、EPUB、UMD、Markdown、代码/文本、图片、音频和视频。</p></div><div class="doc-card"><h3>按需加载更轻</h3><p>OFD、CAD、绘图、PDF、Office、Markdown 和代码高亮链路按格式异步加载，避免所有解析器一次性进入首屏。</p></div><div class="doc-card"><h3>阅读体验更完整</h3><p>Word 保留白色纸张和灰色页面底，PDF 支持缩放、导航窗格和宽度自适应，打开后默认就是可读状态。</p></div></div><h2 id="推荐阅读顺序" tabindex="-1">推荐阅读顺序 <a class="header-anchor" href="#推荐阅读顺序" aria-label="Permalink to &quot;推荐阅读顺序&quot;">​</a></h2><div class="doc-grid"><div class="doc-card"><h3>先看 Demo</h3><p>在线 Demo 和私有化 Demo 都提供按文件类型分组的样例文件盒子，点击样例即可打开并自动收起选择器，适合快速验收全部格式。</p></div><div class="doc-card"><h3>确认格式边界</h3><p>支持格式页列出当前注册的 74 个扩展名、对应渲染链路和真实业务里的适用边界。</p></div><div class="doc-card"><h3>选择接入方式</h3><p>Vue3 使用 <code>@flyfish-group/file-viewer3</code>，Vue2.7 使用 <code>@flyfish-group/file-viewer</code>；React 和纯 JS 包通过 iframe 复用 Vue3 基线产物，适合私有化部署和多系统复用。</p></div><div class="doc-card"><h3>准备发布分发</h3><p>成品分发说明了 npm 包、私有化 viewer 静态产物、文档静态产物和公开成品仓库之间的交付关系。</p></div></div><h2 id="当前重点能力" tabindex="-1">当前重点能力 <a class="header-anchor" href="#当前重点能力" aria-label="Permalink to &quot;当前重点能力&quot;">​</a></h2><ul><li>Word 视图保留灰色页面底和白色纸张，<code>.docx</code> 会按当前可用宽度自适应缩放，长文档缺少显式分页时也会补足视觉分页。</li><li>PPTX 视图增强组合图形坐标映射、旋转/翻转、主题背景、图片裁剪和 EMF 矢量图预览，更适合回看真实汇报模板。</li><li>PDF 视图支持宽度自适应、缩放工具栏、页码状态和可显隐导航窗格。</li><li>OFD 使用 <code>DLTech21/ofd.js</code> 的浏览器端解析和渲染能力，并保持按需异步加载。</li><li>CAD 支持 DXF 在线预览，DWG 作为兼容入口给出转换提示，避免引入不合适的运行时授权链路。</li><li>Excalidraw 使用官方 <code>@excalidraw/excalidraw</code> 导出 SVG，draw.io 使用官方 diagrams.net viewer。</li><li>EPUB 使用 <code>epubjs</code> 提供目录和滚动阅读，UMD 作为电子书格式解析目录和压缩正文，音频使用浏览器原生播放器打开。</li><li>代码和文本使用 <code>highlight.js</code> 轻量高亮，HTML 会按源码展示。</li></ul><h2 id="常用入口" tabindex="-1">常用入口 <a class="header-anchor" href="#常用入口" aria-label="Permalink to &quot;常用入口&quot;">​</a></h2><table tabindex="0"><thead><tr><th>你要做什么</th><th>推荐页面</th></tr></thead><tbody><tr><td>想最快跑起来</td><td><a href="/guide/quickstart">快速开始</a></td></tr><tr><td>想确认所有格式</td><td><a href="/guide/formats">支持格式</a></td></tr><tr><td>想看示例文件和回归建议</td><td><a href="/guide/demo">Demo 说明</a></td></tr><tr><td>想在 Vue 3 中接入</td><td><a href="/guide/quickstart-vue3">Vue3 集成</a></td></tr><tr><td>想在 Vue2.7 中接入</td><td><a href="/guide/quickstart-vue2">Vue2 集成</a></td></tr><tr><td>想在 React 中接入</td><td><a href="/guide/quickstart-react">React 集成</a></td></tr><tr><td>想在非框架页面中接入</td><td><a href="/guide/quickstart-web">纯 JS 集成</a></td></tr><tr><td>想让多个系统共用预览器</td><td><a href="/guide/iframe">Iframe 嵌入</a></td></tr><tr><td>想了解参数和事件</td><td><a href="/guide/usage">组件用法</a></td></tr><tr><td>想下载成品或二开</td><td><a href="/guide/distribution">发布与成品分发</a></td></tr></tbody></table><div class="doc-note"> 如果你只是想快速判断项目是否适合业务，建议先打开 <a href="https://viewer.flyfish.dev" target="_blank" rel="noreferrer">viewer.flyfish.dev</a> 或运行仓库内置 Demo，再用自己的真实附件补一轮回归。React 和纯 JS 组件默认仍只加载你私有部署的 <code>/file-viewer/index.html</code>。 </div>',13)])])}const v=d(i,[["render",o]]);export{n as __pageData,v as default};
